:root {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  color-scheme: light dark;
  color: #1a1a1a;
  background: #f7f7f7;
}

body {
  margin: 0;
  min-height: 100vh;
}

.app {
  max-width: 960px;
  margin: 0 auto;
  padding: 2rem 1.5rem;
}

.header {
  display: flex;
  align-items: baseline;
  gap: 1rem;
  margin-bottom: 1.5rem;
}

.header h1 {
  font-size: 1.5rem;
  margin: 0;
}

.header .date {
  color: #666;
  font-size: 0.9rem;
}

.tabs {
  display: flex;
  gap: 0.25rem;
  border-bottom: 1px solid #ddd;
  margin-bottom: 1.5rem;
}

.tab {
  padding: 0.5rem 1rem;
  background: none;
  border: none;
  border-bottom: 2px solid transparent;
  cursor: pointer;
  font-size: 0.95rem;
  color: #555;
}

.tab.active {
  border-bottom-color: #1a1a1a;
  color: #1a1a1a;
  font-weight: 600;
}

.tab:disabled {
  color: #bbb;
  cursor: default;
}

.badge {
  display: inline-block;
  padding: 0.25rem 0.75rem;
  border-radius: 999px;
  font-weight: 600;
  font-size: 0.85rem;
  letter-spacing: 0.05em;
  color: #fff;
}

.badge.pass { background: #2e7d32; }
.badge.watch { background: #ed8c00; }
.badge.skip { background: #c62828; }
.badge.unknown { background: #757575; }

.card {
  background: #fff;
  border: 1px solid #e5e5e5;
  border-radius: 8px;
  padding: 1.25rem 1.5rem;
}

.card h2 {
  margin: 0 0 1rem 0;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  font-size: 1.1rem;
}

.rationale {
  margin-top: 1rem;
  color: #444;
  line-height: 1.5;
}

.ratios {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
  gap: 0.75rem;
  margin-top: 1rem;
}

.ratio {
  background: #fafafa;
  border: 1px solid #eee;
  border-radius: 6px;
  padding: 0.5rem 0.75rem;
}

.ratio .label {
  color: #777;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.ratio .value {
  font-size: 1.1rem;
  font-weight: 600;
  margin-top: 0.25rem;
}

.empty {
  color: #888;
  font-style: italic;
}

.picker {
  margin-left: auto;
  padding: 0.35rem 0.5rem;
  font-size: 0.9rem;
}
